    import React, { useRef, useState, useEffect, useCallback } from 'react';

    // ... other props ...
    interface NowPlayingProps {
        // ... existing props ...
        onVolumeChange: (volume: number) => void;
        volume: number;
    }
    const NowPlaying: React.FC<NowPlayingProps> = ({
        // ... existing props ...
        onVolumeChange,
        volume,
    }) => {
        // ... existing state and refs ...
        const volumeInputRef = useRef<HTMLInputElement>(null);
        // ... existing event handlers ...
        const handleVolumeWheel = (e: React.WheelEvent<HTMLDivElement>) => {
            e.preventDefault();
            const deltaY = e.deltaY;
            const newVolume = Math.max(0, Math.min(1, volume + deltaY * -0.005));
            onVolumeChange(newVolume);
        };

        const handleTouchEnd = (e: React.TouchEvent<HTMLDivElement>) => {
            const touch = e.changedTouches[0];
            const deltaX = touch.clientX - touchStartRef.current.x;
            const deltaY = touch.clientY - touchStartRef.current.y;
            hasMoved.current = false;
            if (Math.abs(deltaX) > 50 && Math.abs(deltaX) > Math.abs(deltaY)) {
                if (deltaX > 0) onPrev();
                else onNext();
            } else if (deltaY > 100) {
                onClose();
            }
            touchStartRef.current = { x: 0, y: 0 }; // Reset touch start after gesture is done
        };

        // ... return statement ...
         <div
            className={`flex flex-col h-full bg-gray-800 ${isOpen ? 'translate-y-0' : 'translate-y-full'} transition-transform duration-300 ease-in-out`}
            ref={nowPlayingRef}
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
            onWheel={handleVolumeWheel}
        >
            {/* ... other content ... */}
            <input
                type="range"
                min="0"
                max="1"
                step="0.05"
                value={volume}
                onChange={handleVolumeChange}
                ref={volumeInputRef}
                className="w-full h-2 bg-gray-400 rounded-lg appearance-none cursor-pointer range-slider"
            />
         </div>
    }
    export default NowPlaying;
